import java.util.*;
interface Observer { void update(String event); }

class EventBus {
    private List<Observer> observers = new ArrayList<>();
    void subscribe(Observer o)   { observers.add(o); }
    void unsubscribe(Observer o) { observers.remove(o); }
    void publish(String event)   { for (Observer o : observers) o.update(event); }
}

public class Main {
    public static void main(String[] args) {
        EventBus bus = new EventBus();
        Observer logger  = e -> System.out.println("LOG: " + e);
        Observer auditor = e -> System.out.println("AUDIT: " + e);

        bus.subscribe(logger);
        bus.subscribe(auditor);
        bus.publish("login");
        bus.unsubscribe(auditor);
        bus.publish("logout");
    }
}
